/* runs integration tests in shards without skipping any */
const { spawnSync } = require('child_process');
const shardArg = process.argv.find(a=>a.includes('--shard='));
const shard = shardArg ? shardArg.split('=')[1] : '1/1';
const [idx, total] = shard.split('/').map(Number);
// jest will select files via a stable hash
const args = ['jest', '--runInBand', '--selectProjects', 'integration', `--shard=${idx}/${total}`];
const r = spawnSync('npx', args, { stdio: 'inherit' });
process.exit(r.status ?? 1);
